import styled from 'styled-components'
import { heroImg, card, experienceContainer } from './Components'

export const StyledContainer = styled.div`
	width: 100%;
	height: auto;
`

export const StyledHeroImg = styled(heroImg)`
	max-width: 100%;
	height: auto;
	display: flex;
	flex-wrap: wrap;
	flex-direction: column-reverse;

	.HeroText > * {
		max-width: fit-content;
		height: fit-content;
		margin: 3rem 0.5rem;
		background-color: #4e4e4e;
		text-align: center;
		display: flex;
		flex-wrap: wrap;
		color: white;
	}

	img {
		max-width: min-content;
		height: fit-content;
	}
`
export const StyledExperienceContainer = styled(experienceContainer)`
	max-width: 100%;
	height: auto;
	display: flex;
	flex-wrap: wrap;
	max-width: fit-content;
	height: fit-content;

	p, {
		margin: 3rem 0.5rem;
	}
`

export const StyledCard = styled(card)`
	display: flex;
	margin: 4rem auto;
	padding: 2rem;
	background-color: #4e4e4e;
	height: 20rem;
	max-width: 80%;
	justify-content: space-evenly;
	gap: 2rem;

	.Text {
		display: flex;
		flex-direction: column;
		justify-content: space-evenly;
		max-width: 50%;
		flex-basis: 50%;
		background-color: #fff;
		text-align: center;
		padding: 0 1rem;
	}

	p {
		max-width: 25rem;
		display: flex;
		font-size: larger;
		align-self: center;
	}

	a {
		color: black;
	}

	.CardPic {
		max-width: 50%;
		max-height: 100%;
		object-fit: fill;
	}

	img {
		max-width: 100%;
		min-height: 100%;
		max-height: 100%;
	}
`
